import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const crossCulturalCorePhilosopherArticles:Record<string,ArticleSection[]>={
  confucius:[
    section('overview','A teacher of humane order in a broken political world',[
      'Confucius is best approached as a teacher who tried to repair public life by reforming character, ritual practice, and the language of responsibility. He did not present himself as a creator of a new doctrine. The tradition remembers him as a transmitter, editor, and interpreter of older Zhou cultural patterns at a moment when those patterns no longer reliably governed rulers, families, or officials. His importance lies in the claim that political order begins with cultivated persons who know how to honor roles without becoming mechanical servants of status.',
      'The center of his thought is not a single slogan such as obedience, etiquette, or social harmony. It is a dense picture of learning in which ren, often translated as humaneness or authoritative humanity, is formed through li, ritual propriety, and expressed in speech, judgment, family care, friendship, and government. Confucius asks how people can become trustworthy enough that power does not need to rule mainly through punishment. He also asks how inherited forms can become morally alive rather than empty performance.'
    ],['confucianism','chinese-philosophy','ethics'],['mencius','xunzi'],['Analects']),
    section('historical-world','Late Zhou fragmentation and the need for cultivated rule',[
      'Confucius is traditionally dated 551 to 479 BCE, during the late Spring and Autumn period of ancient China. Those dates are more secure than many details of the later legends, but the world around him still requires careful reconstruction. The Zhou royal house retained symbolic prestige while regional states competed for military advantage, administrative control, and diplomatic survival. Aristocratic lineages, court rituals, ancestral practices, and inherited offices remained important, yet actual power increasingly shifted toward ambitious ministers, war leaders, and rulers willing to bypass older restraints.',
      'This political setting gives Confucian ethics its urgency. Confucius was not writing in a settled society where hierarchy already worked. He saw a world in which titles no longer guaranteed virtue, rituals could be performed without reverence, and rulers often treated people as instruments of expansion. His answer was not revolution in the modern sense, but moral and cultural restoration under changed conditions. The past mattered because it preserved models of cultivated rule, not because every inherited arrangement deserved automatic defense.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius'],['Analects']),
    section('sources-and-chronology','The Analects and the problem of access',[
      'Nearly everything philosophical that readers call Confucius comes through the Analects, a layered collection of sayings, dialogues, anecdotes, and memories assembled by followers over time. The text is short, aphoristic, and uneven in tone. Some passages sound close to a teaching scene; others look like later school memory or polemical arrangement. Responsible reading therefore avoids treating every line as a verbatim transcript. The Analects is the classical center of Confucius reception, but it is already an interpreted Confucius.',
      'Later materials such as the Mencius, Xunzi, ritual classics, historical narratives, and imperial traditions develop the image of Confucius in different directions. Some make him a sage almost beyond ordinary humanity; some make him a practical adviser; some make him the authority behind a whole civilizational order. The historical person and the tradition-bearing figure cannot be separated with perfect confidence. The philosophical task is to read the Analects closely while noticing how later Confucians transformed its unfinished conversations into rival theories of human nature, education, ritual, and government.'
    ],['confucianism','chinese-philosophy','epistemology'],['confucius','mencius','xunzi'],['Analects','Mencius','Xunzi']),
    section('ren-and-li','Humaneness and ritual as mutually forming practices',[
      'Ren is one of the most important and difficult terms in the Analects. It names a quality of humane excellence visible in how a person responds to others, uses authority, speaks, grieves, serves, and restrains the self. Confucius rarely defines it abstractly. He answers different students differently, suggesting that ren must be learned through concrete situations and through the correction of particular failures. It is not mere niceness. A humane person can be demanding, exact, and politically serious because care for others includes concern for the forms that make common life possible.',
      'Li includes ritual ceremonies, manners, role-specific conduct, music, mourning, gestures of respect, and the patterned practices through which people learn how to inhabit relationships. Modern readers often hear ritual as external conformity, but for Confucius ritual disciplines feeling and makes respect bodily real. It gives grief a shape, speech a restraint, hierarchy a moral burden, and community a shared grammar. Ren without li risks becoming vague goodwill; li without ren becomes empty choreography. The power of Confucian ethics lies in their interdependence.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius'],['Analects']),
    section('learning-and-character','Learning as lifelong self-cultivation',[
      'Confucius treats learning as a way of becoming a person, not merely as acquisition of information. Study of poetry, history, ritual, and exemplary conduct forms perception and desire. The student learns what to admire, what to be ashamed of, how to listen, when to speak, and how to revise a fault without theatrical self-display. The Analects repeatedly praises love of learning, but learning is measured by conduct. Reciting old forms without changing the self is not wisdom.',
      'This emphasis helps explain why Confucius can be both traditional and experimental. He looks backward to ancient models, yet the past is useful only when it is reanimated by judgment. Students differ in temperament and capacity, so teaching must be responsive. The cultivated person, often called the junzi or exemplary person, is not simply a noble by birth. Confucius reorients nobility toward moral achievement. This move opens a path from hereditary status toward education, even though the social world of the Analects remains far from modern equality.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius'],['Analects']),
    section('names-and-roles','The rectification of names and truthful social language',[
      'A famous Confucian theme is the rectification of names. The point is not pedantic vocabulary control. Social names such as ruler, minister, father, son, friend, and teacher carry expectations about conduct. When people keep titles but abandon the responsibilities that make those titles meaningful, language itself becomes corrupt. A ruler who rules only by appetite is not truly ruler in the normative sense; a minister who flatters rather than remonstrates fails the name he bears.',
      'This idea links ethics, politics, and language. Good order requires that words, roles, and conduct answer to one another. If offices become masks for private gain, punishment may increase while trust collapses. If family roles become domination rather than care, filial language becomes a cover for injury. Confucius therefore asks people to inhabit roles truthfully. The danger is that later readers can turn role ethics into defense of whatever hierarchy exists. The stronger Confucian claim is that status is answerable to moral performance.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius','xunzi'],['Analects']),
    section('family-and-government','Family feeling and public responsibility',[
      'Filial piety is central to Confucian thought, but it should not be reduced to blind obedience. In the Analects, family reverence includes care, mourning, gratitude, continuity with ancestors, and the discipline of serving those from whom one has received life and formation. It also includes remonstrance: a child or minister may need to correct a superior with patience and respect. The family is ethically formative because it is where dependence, affection, authority, and obligation first become visible.',
      'Confucius draws analogies between family and government, yet this analogy is not simple household patriarchy scaled up. Good rule requires moral example, appropriate ritual, light punishment, and the trust of the people. A ruler should attract loyalty through virtue rather than force subjects into compliance through fear. Critics can ask whether family-based politics leaves too much room for paternalism and deference. That criticism matters. Still, Confucius is not saying that power is right because it is old. He is saying that power must become morally educative or it loses legitimacy.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius','mencius','xunzi'],['Analects','Mencius','Xunzi']),
    section('heaven-and-moral-limits','Heaven, fate, and the limits of human control',[
      'The Analects speaks of Heaven, tian, in ways that resist simple classification as personal deity, impersonal order, fate, or moral source. Confucius appears deeply reverent toward Heaven and ritual tradition, yet he is cautious about speculative claims concerning spirits and the afterlife. His emphasis falls on the human task: serve people properly before presuming to serve spirits, and understand life before claiming mastery over death. This restraint is not secular dismissal but ethical prioritization.',
      'Heaven also marks the limits within which moral effort occurs. A person can cultivate virtue, teach, advise rulers, and remain faithful under failure, but cannot guarantee political success. Confucius knew disappointment, exile, and the frustration of being unused by rulers. His confidence in moral cultivation is therefore not naive optimism. It is a discipline for acting rightly when the age may not reward right action. Later Confucians would give more systematic accounts of Heaven, human nature, and cosmic pattern, but the Analects keeps much of this relation open.'
    ],['confucianism','chinese-philosophy','philosophy-of-religion'],['confucius','mencius','xunzi'],['Analects']),
    section('earlier-traditions','A transmitter in conversation with Zhou culture',[
      'Confucius repeatedly presents himself as loving antiquity and transmitting rather than inventing. This claim should not be read as passive repetition. The Zhou legacy supplied him with ritual forms, ancestral reverence, music, poetry, and narratives of exemplary rulers. Yet to transmit a tradition in a time of collapse is already to interpret it. Confucius selects, orders, and morally intensifies inherited practices so that they can answer the violence and opportunism of his own age.',
      'His relation to earlier traditions also explains why later schools could argue over him. Some readers see a conservative defender of hierarchy; others see a reformer who turns noble status into moral achievement; others emphasize his religious reverence, political realism, or educational humanism. The Analects itself gives support to several emphases because it is not a treatise. It is a record of teaching moments. Its power comes from showing a person trying to keep inherited forms alive by making them ethically accountable.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius'],['Analects']),
    section('later-confucians','Mencius, Xunzi, and the growth of Confucian philosophy',[
      'Confucius became the ancestor of a tradition, but later Confucians disagreed sharply about how to defend and complete his project. Mencius emphasizes the sprouts of virtue and argues that human nature is good in the sense that people have incipient moral tendencies that must be cultivated. He develops a more explicit account of benevolent government and of the moral limits of rulership. The result is a warmer, more confidence-bearing extension of Confucian self-cultivation.',
      'Xunzi, by contrast, argues that human nature is bad or wayward and that goodness comes through conscious effort, ritual, teachers, and social artifice. He turns li into an explicitly constructive achievement that transforms raw desire into ordered life. Both thinkers claim Confucius, and both illuminate different sides of the Analects. Later imperial, Neo-Confucian, and modern Confucian traditions would continue this pattern: Confucius becomes a shared origin for disputes about nature, education, metaphysics, political authority, and moral psychology.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius','mencius','xunzi'],['Analects','Mencius','Xunzi']),
    section('misunderstandings-and-tensions','Common misunderstandings and real tensions',[
      'The most common misunderstanding is that Confucius teaches mere conformity. He does care about roles, deference, and inherited form, but he also requires moral judgment, sincere cultivation, remonstrance, and the correction of corrupt names. Another misunderstanding treats Confucian ritual as ornamental politeness. For Confucius, ritual forms the emotions and makes respect durable. A third misunderstanding turns harmony into avoidance of conflict. Confucian harmony requires properly ordered difference, not the suppression of every disagreement.',
      'There are also genuine tensions that should not be smoothed away. A role-centered ethic can discipline arbitrary power, but it can also be used to protect hierarchy. Reverence for antiquity can preserve moral memory, but it can also resist needed change. Family devotion can teach gratitude and care, but it can also create conflicts with impartial justice. Confucius remains philosophically alive because his solution to disorder is neither individual autonomy nor state command, but cultivated relational life. That solution is powerful, incomplete, and still contested.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius','mencius','xunzi'],['Analects']),
    section('reading-strategy','How to read Confucius well',[
      'Begin with the Analects slowly rather than looking for a system all at once. Notice who is asking the question, what kind of person seems to need the answer, and how often Confucius refuses a single formula. Track recurring terms such as ren, li, junzi, filial piety, learning, trustworthiness, and Heaven. It helps to read passages in clusters, because a sentence that looks rigid in isolation may become more flexible when placed beside other conversations about correction, sincerity, and judgment.',
      'After the Analects, read selections from Mencius and Xunzi to see how later Confucians build rival philosophical architectures from Confucian materials. Keep three cautions in view. First, do not impose later imperial orthodoxy back onto the early teacher too quickly. Second, do not romanticize Confucius as a modern liberal educator. Third, do not dismiss the tradition as etiquette before asking what kind of person rituals are meant to form. Confucius is most rewarding when read as a practical philosopher of moral formation under political strain.'
    ],['confucianism','chinese-philosophy','ethics'],['confucius','mencius','xunzi'],['Analects','Mencius','Xunzi'])
  ],
  laozi:[
    section('overview','The Dao as the source and correction of human striving',[
      'Laozi names both a legendary sage and the authority associated with the Daodejing, one of the most influential texts in Chinese philosophy. The figure is traditionally portrayed as an older contemporary or critic of Confucius, but the historical basis for that portrait is uncertain. The text itself is a compact sequence of sayings, images, paradoxes, and political reflections centered on dao, the way or course that precedes and exceeds named things. It teaches by unsettling the habits through which people try to control life.',
      'The Daodejing does not offer a program of laziness, irrationalism, or mystical escape. It asks why forceful assertion so often produces the opposite of what it seeks. Rulers who grasp at control multiply disorder; people who chase status lose touch with sufficiency; language that freezes reality into fixed oppositions misses the generative movement beneath them. Laozi becomes philosophically important because the text connects metaphysics, ethics, politics, and spiritual discipline through a single suspicion: aggressive human cleverness may be the deepest source of confusion.'
    ],['daoism','chinese-philosophy','metaphysics'],['laozi','zhuangzi'],['Daodejing']),
    section('legend-and-chronology','Legendary biography and uncertain composition',[
      'The traditional biography says that Laozi served as an archivist, met Confucius, left the Zhou world in disgust, and composed the Daodejing at the request of a border guard. These stories are philosophically rich but historically fragile. They present Laozi as a keeper of old wisdom who withdraws when public order becomes corrupt. They also stage Daoist teaching as something reluctant, given at the edge of civilization. Modern scholarship generally treats the received figure with caution and the text as the product of layered composition.',
      'The Daodejing likely took shape over time in the Warring States intellectual world, though dating remains debated. Excavated manuscript traditions, including versions from Mawangdui and Guodian, show that the text circulated in forms that differed from the later received arrangement. This does not make the work less important. It means that Laozi should be read as a textual and philosophical node rather than as a fully recoverable individual author. Chronology caution is part of philosophical honesty here, not a reason to dismiss the depth of the text.'
    ],['daoism','chinese-philosophy','epistemology'],['laozi','confucius'],['Daodejing']),
    section('dao-and-naming','The way that cannot be captured by names',[
      'The Daodejing famously begins by warning that the dao that can be spoken as a fixed dao is not the constant dao. This is not a claim that language is useless. The text itself is made of language and uses images with great care. The warning is that naming carves reality into manageable objects and contrasts, while dao names the generative course from which distinctions arise. When a name becomes a possession, people confuse their map with the movement it only partially tracks.',
      'Dao is not simply a thing among things, a god who commands the world, or a law imposed from outside. It is the source, pattern, and inexhaustible process through which beings arise and return. The text often speaks indirectly: water, valley, uncarved block, mother, root, infant. These images train the reader away from domination and toward receptivity. They do not define dao once for all. They create a way of perceiving in which what seems low, soft, empty, or yielding may be more basic than what seems hard and commanding.'
    ],['daoism','chinese-philosophy','metaphysics'],['laozi','zhuangzi'],['Daodejing']),
    section('de-and-power','De as power, potency, and unforced presence',[
      'De is often translated as virtue, but in the Daodejing it also means potency, efficacy, or the distinctive power by which a being follows dao. This differs from moral virtue understood mainly as rule compliance or public reputation. De is what makes a person, ruler, or community effective without coercive display. The highest de does not advertise itself as virtue. It works by allowing things to develop according to their own tendencies rather than by forcing them into a rigid plan.',
      'This account of power reverses ordinary admiration. The person who needs to announce strength may already be weak; the ruler who multiplies prohibitions may reveal failure to govern; the moralist who performs benevolence after dao has been lost may signal decline rather than excellence. These provocations do not mean that ethical qualities are worthless. They suggest that virtues become strained and theatrical when severed from a deeper alignment with dao. De is cultivated by reducing interference, desire, and self-importance until action no longer has to push so hard.'
    ],['daoism','chinese-philosophy','ethics'],['laozi','zhuangzi'],['Daodejing']),
    section('wuwei','Wuwei and the discipline of noncoercive action',[
      'Wuwei is commonly translated as nonaction, but it does not mean doing nothing in a crude sense. It means action that does not force, strain, overmanage, or impose a rigid egoistic design on the situation. Skilled action can be intensely responsive while seeming effortless because it follows the grain of things. The Daodejing applies this pattern to personal conduct, political rule, and cosmic understanding. One acts best by removing the compulsions that make action clumsy.',
      'The political edge of wuwei is especially important. A ruler who trusts constant intervention may create the very disorder that justifies more intervention. Heavy taxation, military ambition, punitive law, and competitive display train people into cunning and resentment. Wuwei government reduces unnecessary interference so that people can recover simple patterns of life. Readers may disagree about whether this is a practical statecraft doctrine, a utopian critique of state power, or a spiritual metaphor. The text deliberately speaks across those levels.'
    ],['daoism','chinese-philosophy','ethics'],['laozi','zhuangzi'],['Daodejing']),
    section('simplicity-and-desire','Simplicity, desire, and the uncarved block',[
      'The Daodejing repeatedly praises simplicity, emptiness, softness, and the uncarved block. These images criticize the multiplication of artificial desires. When social life teaches people to chase rare goods, refined status, clever distinction, and visible success, desire becomes restless. Scarcity is intensified by comparison. Laozi does not deny ordinary needs or bodily life. He asks why human communities turn enough into permanent insufficiency by making prestige and accumulation the measure of worth.',
      'The uncarved block symbolizes a condition before social carving has divided, ranked, and overdefined experience. It is not a wish to become ignorant or infantile. It is an attempt to recover a more primal responsiveness beneath artificial ambitions. Emptiness also becomes useful: a bowl works because of the hollow space, a room because of the empty interior, a valley because it receives. These images teach that absence is not mere lack. What is not asserted can be the condition for life to move.'
    ],['daoism','chinese-philosophy','ethics'],['laozi'],['Daodejing']),
    section('politics-and-war','Small states, low rule, and suspicion of war',[
      'Laozi is a major political thinker because the Daodejing questions the glamour of rule. It praises leaders whose work is barely noticed and criticizes rulers who depend on punishment, surveillance, ambition, and military glory. The best ruler does not seek personal fame. Good government leaves people able to live without being constantly mobilized for state projects. The text sometimes imagines a small community with simple tools, plain food, local contentment, and little desire to travel or conquer.',
      'Its suspicion of war is direct. Weapons are ominous instruments, and victory should be marked with mourning rather than celebration. This does not necessarily make the text pacifist in every conceivable circumstance, but it strips war of nobility. Force may sometimes compel a result, but it cannot create deep order. The political teaching is unsettling because it treats much of what states call strength as a symptom of failure. To rule by dao is to refuse the intoxication of command.'
    ],['daoism','chinese-philosophy','ethics'],['laozi'],['Daodejing']),
    section('relation-to-confucianism','Laozi and the Confucian challenge',[
      'Daoist and Confucian traditions are often contrasted through ritual versus spontaneity, social order versus naturalness, or moral cultivation versus effortless alignment. These contrasts capture real tensions, but they can become too simple. The Daodejing criticizes the artificiality of moral display, the decline from dao into named virtues, and the way rules can multiply hypocrisy. From that angle, Confucian ritual may look like a late-stage remedy for a world already separated from the source.',
      'Yet the relationship is not only opposition. Both traditions worry about disorder, bad rulers, false prestige, and the deformation of desire. Both ask how a person can be formed beyond appetite and ambition. The difference lies partly in trust: Confucians often trust disciplined cultural forms to shape humane persons, while Laozi warns that deliberate improvement can intensify the disease. Later Chinese thought repeatedly placed these traditions in argument, combination, and mutual correction rather than treating them as sealed boxes.'
    ],['daoism','confucianism','chinese-philosophy'],['laozi','confucius','zhuangzi'],['Daodejing','Analects']),
    section('textual-style','Paradox, image, and textual layers',[
      'The Daodejing teaches through compression. A single chapter may combine cosmology, politics, personal discipline, and paradox in a few lines. This style invites overconfident paraphrase. When the text says the soft overcomes the hard, it does not merely state a rule; it asks the reader to see strength differently. When it praises not knowing, it does not praise confusion; it attacks the conceit that classificatory cleverness equals wisdom.',
      'Because the text is layered and aphoristic, interpreters disagree about structure. Some read it mainly as political advice for rulers, some as mystical metaphysics, some as a manual of self-cultivation, some as a critique of elite civilization, and some as a collection that preserves several voices. These readings need not exclude one another. The text works precisely by making the same image move across registers. Water is cosmological, ethical, political, and meditative at once.'
    ],['daoism','chinese-philosophy','epistemology'],['laozi'],['Daodejing']),
    section('later-daoism','Later Daoist transformations',[
      'The Daodejing became foundational for Daoist philosophy, religious Daoism, Chinese political thought, poetry, meditation, and later practices concerned with body, cosmos, longevity, and ritual. Its relation to later organized Daoist traditions is real but complex. The early text does not contain the full institutions, deities, liturgies, alchemical systems, or monastic forms that developed later. It supplied vocabulary and authority that later communities reinterpreted for new religious and practical aims.',
      'Zhuangzi develops a different but related Daoist voice, more playful, skeptical, and story-driven. Later commentators read Laozi through metaphysics of being and nonbeing, through Buddhist categories, through statecraft, and through internal cultivation. Outside China, the Daodejing has often been translated as universal wisdom detached from its historical context. Its global reception is valuable, but it can also erase the Warring States pressures and Chinese debates that gave the text its sharpness.'
    ],['daoism','chinese-philosophy','metaphysics'],['laozi','zhuangzi'],['Daodejing','Zhuangzi']),
    section('misunderstandings-and-tensions','Common misunderstandings and interpretive risks',[
      'One misunderstanding is that Laozi teaches passivity. Wuwei is better understood as noncoercive efficacy, not paralysis. Another is that the text rejects all knowledge. It rejects grasping cleverness and rigid naming, while using subtle observation to reshape understanding. A third is that Daoism is simply individual spiritual retreat. The Daodejing is deeply political, even when its politics call for restraint, smallness, and withdrawal from glory.',
      'There are genuine tensions. If rulers practice noninterference, does that protect people from oppression or leave existing harms untouched? If language distorts dao, how can teaching avoid distortion? If simplicity is praised, who decides which forms of culture are corrupt? These questions should stay active. Laozi is not a set of decorative paradoxes. It is a radical inquiry into whether human beings can stop making their world less livable by trying to master it too aggressively.'
    ],['daoism','chinese-philosophy','ethics'],['laozi','zhuangzi'],['Daodejing']),
    section('reading-strategy','How to read Laozi without turning it into slogans',[
      'Read the Daodejing in more than one translation if possible, because key terms such as dao, de, wuwei, ziran, and pu carry ranges of meaning that no single English rendering captures. Move slowly by chapter clusters rather than looking for a linear treatise. Ask how each image works: water, valley, mother, infant, root, uncarved block, empty vessel. The images are not ornaments. They are the method by which the text trains perception.',
      'Keep the historical and textual cautions near the surface. Laozi as a named sage, Laozi as a legendary critic of Confucius, and Laozi as the authority of a layered text are not identical. Read beside selections from the Analects and Zhuangzi to hear the debate about ritual, spontaneity, language, and power. The best first question is not whether Laozi is practical in a modern policy sense. It is what kinds of striving the text exposes as self-defeating.'
    ],['daoism','confucianism','chinese-philosophy'],['laozi','confucius','zhuangzi'],['Daodejing','Analects','Zhuangzi'])
  ],
  zhuangzi:[
    section('overview','Freedom through transformation of perspective',[
      'Zhuangzi is the most playful and philosophically disorienting voice of early Daoism. Where the Daodejing often speaks in compressed images of rule and cosmic source, the Zhuangzi unfolds through stories, jokes, absurd conversations, skilled artisans, talking trees, useless gourds, dreaming butterflies, and sages who seem to have slipped the grip of ordinary distinctions. Its question is not simply how to live naturally. It asks how people become imprisoned by fixed perspectives and how they might move more freely among the transformations of things.',
      'This freedom is not escape into private fantasy. It is a disciplined loosening of rigid judgments about usefulness, success, identity, life, death, and knowledge. The text repeatedly shows people mistaking a local standpoint for the measure of reality. The narrow creature mocks what it cannot imagine; the official values what serves office; the disputant clings to a distinction because victory matters. Zhuangzi teaches by making the reader laugh at the smallness of those measures and then notice the same smallness within the self.'
    ],['daoism','chinese-philosophy','ethics'],['zhuangzi','laozi'],['Zhuangzi']),
    section('context-and-person','Warring States pressure and an elusive author',[
      'Zhuangzi is traditionally associated with Master Zhuang, often dated to the fourth century BCE, during the Warring States period. The world was marked by military competition, bureaucratic centralization, social mobility, and intense debate among Confucians, Mohists, Legalists, Daoists, logicians, and other thinkers. Philosophers advised rulers, built schools, criticized rivals, and asked how order could be created in a violent age. The Zhuangzi speaks from inside that ferment while refusing many of its ambitions.',
      'The historical person remains elusive. Anecdotes portray Zhuangzi as poor, independent, funny, and unwilling to trade freedom for office, but such stories are literary as much as biographical. The received text is not the work of one hand in any simple sense. It contains layers, schools, and voices. The seven Inner Chapters are often treated as closest to the strongest early Zhuangzian voice, while Outer and Miscellaneous Chapters preserve related developments and later materials. This layered character is a feature of interpretation, not a defect to hide.'
    ],['daoism','chinese-philosophy'],['zhuangzi','laozi','confucius'],['Zhuangzi']),
    section('text-and-style','Stories as philosophical instruments',[
      'The Zhuangzi rarely argues like a formal treatise. It stages encounters in which ordinary criteria fail. A huge fish becomes a bird; a butterfly dream unsettles identity; a tree survives because it is useless; Cook Ding carves an ox by following spaces rather than hacking through resistance. These stories are not merely illustrations of doctrines stated elsewhere. They are experiments in attention. By entering them, readers feel the instability of the categories they brought with them.',
      'This literary form makes the text difficult to summarize without damage. A story may mock Confucius in one place and make him a Daoist teacher in another. It may appear skeptical about knowledge, yet show extraordinary forms of skill. It may praise uselessness, yet be intensely useful as a critique of harmful usefulness. Zhuangzi writes philosophy that resists capture by the very classifications philosophy often seeks. The style performs the teaching: it keeps the mind from settling too quickly.'
    ],['daoism','chinese-philosophy','epistemology'],['zhuangzi','confucius'],['Zhuangzi']),
    section('perspective-and-relativity','Perspectival limits without simple relativism',[
      'One of the most famous themes in the Zhuangzi is the relativity of perspectives. Creatures, people, and schools judge from where they stand. What is large to one being is small to another; what is useful to one office is useless to another life; what appears noble within one convention may look absurd from a wider view. The text exposes the provincialism of every claim that forgets its own standpoint.',
      'This does not reduce Zhuangzi to the claim that every view is equally good. Some perspectives are cramped, anxious, violent, and self-defeating. Others are more spacious because they can roam among differences without needing to freeze them. The sage does not possess a final theory that defeats all others. The sage moves with the transformations of things and uses distinctions without being used by them. Zhuangzian freedom is therefore not flat relativism but a cultivated flexibility in relation to perspective.'
    ],['daoism','chinese-philosophy','epistemology'],['zhuangzi'],['Zhuangzi']),
    section('language-and-disputation','Language, disputation, and the limits of winning',[
      'The Zhuangzi is fascinated by language because names both reveal and trap. Disputants divide the world, defend their divisions, and treat victory in argument as proof that reality has been mastered. The text often targets the culture of debate associated with rival schools. It asks whether distinctions such as this and that, right and wrong, useful and useless, can ever be final when they arise within changing contexts and partial interests.',
      'Yet Zhuangzi does not simply reject language. The text is linguistically brilliant. It uses paradox, humor, repetition, and shifting voices to loosen attachment to fixed names. A distinction can be useful when handled lightly, like a tool suited to a moment. It becomes dangerous when people identify themselves with it and cannot respond to what exceeds it. The problem is not speech as such, but speech hardened into possession. Good language may be language that helps us forget the need to win.'
    ],['daoism','chinese-philosophy','epistemology'],['zhuangzi','laozi'],['Zhuangzi']),
    section('spontaneity-and-skill','Skill, spontaneity, and following the grain',[
      'Zhuangzi often presents skilled activity as a model for Daoist life. Cook Ding does not impose force on the ox; he follows the spaces and moves with the structure of the situation. The swimmer, artisan, ferryman, cicada catcher, and other figures show action that has passed beyond anxious rule-following. Their excellence is embodied, responsive, and unforced. It is not anti-intellectual in a crude sense. It is intelligence so deeply trained that it no longer appears as calculation.',
      'This theme clarifies spontaneity. Ziran, often rendered as naturalness or self-so, is not impulsiveness. A novice who ignores form is not free. The skilled person has undergone discipline until action can be fluid. The difference from some Confucian accounts lies in suspicion toward socially visible measures of cultivation. Zhuangzi values forms of attunement that may appear useless, lowly, or eccentric to public life. Wisdom may be closer to an artisan following the grain than to an official announcing principles.'
    ],['daoism','chinese-philosophy','ethics'],['zhuangzi','laozi'],['Zhuangzi']),
    section('usefulness-and-uselessness','The usefulness of uselessness',[
      'The Zhuangzi repeatedly praises what ordinary society calls useless. A gnarled tree escapes the axe because its wood does not suit carpenters; a large gourd becomes useless only because someone imagines a narrow use; an awkward body may keep a person from conscription or court service. These stories overturn the assumption that value is measured by service to current social purposes. Sometimes being useful to power is exactly what destroys a thing.',
      'The usefulness of uselessness is not a simple command to be incompetent. It asks whose use is being served and what forms of life are excluded by dominant measures. A society organized around office, productivity, war, and reputation will call many forms of freedom useless. Zhuangzi turns that judgment around. What cannot be easily recruited may preserve life, imagination, and wandering. The theme has political force because it resists the conversion of every being into material for state or social ambition.'
    ],['daoism','chinese-philosophy','ethics'],['zhuangzi'],['Zhuangzi']),
    section('life-death-and-transformation','Life, death, and transformation',[
      'Zhuangzi treats life and death as transformations within dao rather than as absolute opposites to be mastered by fear. Stories of mourning, illness, and bodily change often shock readers because they refuse expected emotional scripts. When a wife dies, when a body becomes deformed, or when a person faces mortality, the text asks whether grief and horror come partly from insisting that one phase of transformation should be permanent. To accept transformation is not to deny pain. It is to loosen the demand that reality conform to a preferred form.',
      'This acceptance can be misread as coldness. The Zhuangzi is not telling people to feel nothing. It questions the concepts through which feelings become bondage. Life and death are part of a larger process that exceeds the self-centered standpoint. The butterfly dream captures this instability: was Zhuang Zhou dreaming he was a butterfly, or is a butterfly dreaming it is Zhuang Zhou? The point is not a puzzle to solve once for all. It is an experience of identity as transformation rather than fixed ownership.'
    ],['daoism','chinese-philosophy','metaphysics'],['zhuangzi'],['Zhuangzi']),
    section('politics-and-withdrawal','Office, power, and the refusal to be trapped',[
      'Zhuangzi is deeply suspicious of political office. Stories portray offers of employment as temptations that can capture a person in danger, vanity, and service to violence. The famous image of preferring to drag a tail in the mud rather than become a venerated dead turtle in a court shrine expresses this refusal with comic force. Better an obscure living freedom than honored usefulness to power.',
      'The political teaching is not a modern theory of rights or a simple rejection of all public concern. It is a diagnosis of how office can deform perception. When rulers seek techniques for control, philosophers may become tools of domination. When ambition seeks recognition, the self becomes dependent on dangerous patrons. Zhuangzi therefore places freedom at a distance from official success. Modern readers can ask whether withdrawal abandons victims of bad rule, but the text remains a powerful critique of intellectual service to power.'
    ],['daoism','chinese-philosophy','ethics'],['zhuangzi','confucius'],['Zhuangzi']),
    section('relation-to-laozi-and-confucius','Relations to Laozi, Confucius, and rival schools',[
      'Zhuangzi and Laozi are grouped together as Daoist classics, but their voices differ. Laozi often speaks in compressed counsel about dao, de, wuwei, and rule. Zhuangzi multiplies perspectives until fixed counsel becomes suspect. Both criticize coercive striving and artificial status. Both value softness, receptivity, and alignment with dao. Yet Zhuangzi is more theatrical, skeptical, and fascinated by language and transformation. Reading them together shows Daoism as a family of questions rather than a single doctrine.',
      'Confucius appears throughout the Zhuangzi in unstable roles. Sometimes he is mocked as a ritualist trapped in social categories; sometimes he becomes a vehicle for Daoist insight. This ambivalence matters. The text knows Confucian vocabulary and reworks it from within. It also engages rival disputers whose confidence in distinctions, utility, and reform appears narrow. Zhuangzi is not outside the Hundred Schools conversation. It is one of its most radical internal critics.'
    ],['daoism','confucianism','chinese-philosophy'],['zhuangzi','laozi','confucius'],['Zhuangzi','Daodejing','Analects']),
    section('influence-and-reception','Influence in Chinese and global thought',[
      'The Zhuangzi influenced Daoist religion, Chinese Buddhism, Chan and Zen traditions, poetry, painting, literary theory, and later philosophical reflection on freedom, language, and nature. Buddhist readers found resonances with emptiness, nonattachment, and the critique of conceptual fixation, though the traditions should not be collapsed. Literati found in Zhuangzi a language for withdrawal, eccentricity, and aesthetic freedom. Political readers found both a critique of power and a problem of disengagement.',
      'Modern global reception often celebrates Zhuangzi as a philosopher of relativism, ecology, spontaneity, or anti-authoritarian freedom. These readings can be illuminating, but they can also flatten the text into modern preferences. Zhuangzi is stranger than many appropriations allow. It does not simply tell people to be themselves, trust nature, or reject society. It asks what the self is, what nature means, and how social distinctions shape even the desire to escape them.'
    ],['daoism','chinese-philosophy','buddhist-philosophy'],['zhuangzi','laozi','nagarjuna'],['Zhuangzi']),
    section('reading-strategy','How to read Zhuangzi without pinning it down too fast',[
      'Begin with the Inner Chapters, especially the free and easy wandering, discussion on making all things equal, nourishing life, and great ancestral teacher materials. Read stories more than once before translating them into thesis statements. Ask what standpoint each character occupies, what assumption becomes ridiculous, and how the story changes the emotional feel of a concept such as usefulness, death, or knowledge. The text often teaches by making a familiar confidence feel small.',
      'Then read selections from the Outer and Miscellaneous Chapters with awareness that the received text is layered. Compare Zhuangzi with the Daodejing and the Analects to see how Daoist and Confucian questions intersect. Hold three cautions. Do not turn perspectivism into easy anything-goes relativism. Do not turn spontaneity into impulse. Do not turn uselessness into a slogan for withdrawal from every obligation. Zhuangzi works best as a companion in loosening fixations that have begun to pass for reality.'
    ],['daoism','confucianism','chinese-philosophy'],['zhuangzi','laozi','confucius'],['Zhuangzi','Daodejing','Analects'])
  ],
  buddha:[
    section('overview','A path for ending suffering through understanding',[
      'The Buddha, traditionally known as Siddhartha Gautama or Shakyamuni, stands at the origin of Buddhist philosophy as a teacher who diagnosed suffering and taught a path of liberation. His thought is not primarily a set of speculative theses about the universe. It is a disciplined response to the problem of dukkha: suffering, unsatisfactoriness, vulnerability, and the instability that marks conditioned life. Philosophy, meditation, ethics, and community become inseparable because the point is to transform the causes of bondage.',
      'The Buddha is also a historical and textual challenge. Dates vary by scholarly tradition, and many details of the life story are shaped by later memory, devotion, and literary pattern. The central philosophical figure is available through canons preserved by Buddhist communities in different languages and schools, not through writings authored by the Buddha himself. This does not make inquiry impossible. It means that readers must distinguish early strata, later elaboration, and the living religious significance that made preservation possible.'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['buddha','nagarjuna'],['Dhammapada']),
    section('historical-context','North Indian religious ferment and the sramana world',[
      'The Buddha lived in northern India sometime around the middle of the first millennium BCE, in a world of expanding kingdoms, urbanization, trade, and debate among Brahmanical ritual specialists and non-Brahmanical renunciant movements. The sramana environment included seekers who practiced austerity, meditation, celibacy, wandering, and philosophical inquiry outside ordinary household life. Questions about rebirth, karma, liberation, self, ritual, and knowledge were intensely contested. Buddhism emerged from this shared field rather than from isolation.',
      'This context matters because the Buddha rejects some available answers while transforming others. He does not center liberation on Vedic sacrifice, hereditary ritual status, or metaphysical speculation about an eternal self. He also rejects extreme self-mortification after experimenting with asceticism. The middle way is not bland compromise. It is a practical and philosophical refusal of both indulgence and destructive austerity. Liberation requires understanding the processes that generate suffering, not punishing the body or pleasing divine powers through inherited ritual alone.'
    ],['buddhist-philosophy','indian-philosophy','philosophy-of-religion'],['buddha'],['Dhammapada']),
    section('life-story-and-caution','Life story, awakening, and caution about legend',[
      'Traditional biographies tell of a prince shielded from suffering who encounters old age, sickness, death, and a renunciant, leaves palace life, studies with teachers, practices severe austerities, awakens under the Bodhi tree, teaches for decades, and dies after establishing a community. This story is philosophically powerful because it dramatizes the shock of impermanence and the inadequacy of sheltered pleasure. Yet its details are shaped by devotional literature and should not be treated as neutral chronicle.',
      'Chronology caution does not diminish the story. Buddhist life narratives function as maps of existential recognition: comfort fails to answer mortality; teachers can guide but not substitute for awakening; extremes must be abandoned; insight becomes compassion through teaching. The historical Buddha probably did teach within a renunciant community and gather followers across social lines, but exact episodes are difficult to verify. Reading well means allowing the life story to carry philosophical meaning while marking the boundary between history, legend, and practice.'
    ],['buddhist-philosophy','indian-philosophy'],['buddha'],['Dhammapada']),
    section('sources-and-canons','Discourses, monastic memory, and textual plurality',[
      'The Buddha did not leave writings. Teachings were preserved orally by communities and later written down in canons such as the Pali Canon and parallel collections in other languages. Early Buddhist texts include discourses, monastic rules, and analytical materials that organize doctrine. These texts often begin with formulaic settings and repeat key structures, reflecting oral preservation. They are indispensable but not simple transcripts. The voice of the Buddha in scripture is a tradition-mediated voice.',
      'Different Buddhist schools preserved different collections, and later Mahayana sutras expanded the scriptural world with new philosophical and devotional visions. A historically cautious reader does not have to decide that only the earliest layer matters. Instead, one can ask what problems each layer addresses. Early discourses emphasize the path, impermanence, not-self, dependent arising, discipline, and liberation. Later traditions ask how buddhahood, emptiness, compassion, bodhisattva practice, and universal liberation should be understood. The Buddha becomes the source of a continuing philosophical conversation.'
    ],['buddhist-philosophy','indian-philosophy','epistemology'],['buddha','nagarjuna','vasubandhu'],['Pali Canon','Dhammapada']),
    section('four-noble-truths','The four noble truths as diagnosis and therapy',[
      'The four noble truths are often presented as the heart of the Buddha teaching: suffering, the origin of suffering, the cessation of suffering, and the path leading to cessation. They are not merely propositions to believe. They function like a medical diagnosis. One recognizes the condition, understands its cause, sees that it can end, and follows a treatment. This structure explains why Buddhist philosophy is practical without being anti-intellectual. Correct understanding is part of therapy.',
      'Dukkha includes obvious pain, but also the unsatisfactoriness of pleasures that change, identities that must be defended, bodies that age, and experiences that cannot be possessed permanently. The origin of dukkha is craving, ignorance, and attachment, not desire in every ordinary sense. Cessation is not annihilation of a real self, but release from the processes that bind experience to grasping. The path includes ethical conduct, meditation, and wisdom. It is a training of the whole person.'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['buddha'],['Dhammapada']),
    section('dependent-origination','Dependent origination and conditioned life',[
      'Dependent origination teaches that phenomena arise in dependence on conditions. Nothing in ordinary experience exists as an isolated, self-grounded entity. Suffering arises through patterns: ignorance conditions formations, formations condition consciousness, and so on through birth, aging, and death in the classical twelvefold chain. The details of the formula are interpreted in different ways, but the central insight is that bondage is produced. Because it is conditioned, it can be understood and interrupted.',
      'This teaching avoids two extremes. It rejects the idea of a permanent independent self that owns experience from behind the scenes. It also rejects the idea that events are random or morally meaningless. Karma is not fate imposed by an external judge. It concerns intentional action and its consequences within conditioned processes. Dependent origination gives Buddhist thought its analytical power: instead of asking what the self ultimately is, it asks how the sense of self, craving, and suffering are constructed moment by moment and across lives.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['buddha','nagarjuna'],['Pali Canon']),
    section('not-self','Not-self and the analysis of personhood',[
      'The doctrine of not-self, anatta or anatman, is one of the most difficult and important Buddhist teachings. It does not simply say that people do not exist in any sense. It denies that the changing aggregates of body, feeling, perception, formations, and consciousness contain or belong to a permanent, independent self. What people call a person is a dynamic process, dependently arisen and conventionally identifiable, but not an unchanging owner behind experience.',
      'The teaching is therapeutic as well as metaphysical. Clinging to self makes experience defensive: this is mine, this I am, this is myself. When the aggregates are seen as impermanent and not-self, attachment loosens. The point is not self-hatred or nihilism. It is relief from the burden of defending a fiction of control. Later Buddhist philosophers would debate how to account for memory, moral responsibility, rebirth, and liberation without a permanent self. Those debates show the philosophical depth of a teaching sometimes reduced to a slogan.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['buddha','nagarjuna','vasubandhu'],['Pali Canon']),
    section('ethics-meditation-wisdom','Ethics, meditation, and wisdom as one path',[
      'The noble eightfold path includes right view, intention, speech, action, livelihood, effort, mindfulness, and concentration. These are not isolated modules. Ethical conduct stabilizes life and reduces harm; meditation trains attention and reveals the arising and passing of experience; wisdom understands impermanence, suffering, and not-self. The path is embodied in habits of speech, livelihood, community, and perception. It is not a private intellectual conclusion added to an unchanged life.',
      'This unity matters for philosophy. The Buddha does not treat knowledge as detached observation. Ignorance is affective and practical: it appears as craving, aversion, and misperception. Therefore insight requires training attention and conduct. Meditation is not mere relaxation, and ethics is not mere rule-following. Each supports the other. A person who sees impermanence more clearly may cling less; a person who harms less may see more clearly. Liberation is the transformation of how experience is known, valued, and enacted.'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['buddha'],['Dhammapada']),
    section('community-and-social-order','Sangha, caste critique, and practical institutions',[
      'The Buddha founded a sangha, a community of monks and nuns, alongside lay followers who supported and learned from the renunciant community. The institutional details developed over time, but the idea is philosophically important. Liberation is not only an inner event; it requires forms of life that support discipline, teaching, confession, restraint, and shared memory. The monastic rule creates a social technology for reducing craving and sustaining practice across generations.',
      'Early Buddhist texts also challenge the idea that spiritual worth depends on birth status. A person becomes noble through conduct and insight rather than caste lineage. This is a significant ethical revaluation, though Buddhist societies have varied greatly in how far they challenged social hierarchy in practice. The Buddha teaching therefore has both radical and institutional dimensions. It opens liberation beyond hereditary ritual privilege, while also creating disciplined communities with rules, ranks, and dependence on lay-monastic relations.'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['buddha'],['Pali Canon']),
    section('unanswered-questions','Silence, speculation, and the poisoned arrow',[
      'The Buddha is often portrayed as refusing certain metaphysical questions: whether the world is eternal or not, finite or infinite, whether the liberated one exists after death, does not exist, both, or neither. The famous poisoned arrow image suggests that a person wounded by suffering should not delay treatment until every speculative question is answered. This does not mean Buddhism lacks metaphysics. It means that speculation is judged by its relation to liberation.',
      'The refusal is philosophically subtle. Some questions may be wrongly framed because they assume a self or world structure that the teaching has already undermined. Others may be practically useless for ending suffering. The Buddha redirects attention from cosmic curiosity to conditioned arising and cessation. Later Buddhist thinkers, including Nagarjuna, would develop powerful philosophical arguments from this restraint. The silence is not emptiness of thought. It is a discipline about which questions conduce to freedom and which deepen attachment to views.'
    ],['buddhist-philosophy','indian-philosophy','epistemology'],['buddha','nagarjuna'],['Pali Canon']),
    section('later-influence','From early Buddhism to vast philosophical traditions',[
      'The Buddha teaching generated a wide range of Buddhist philosophical traditions. Abhidharma systems analyzed experience into momentary factors and debated what ultimately exists. Mahayana traditions developed ideals of the bodhisattva, emptiness, compassion, and buddhahood. Madhyamaka, associated with Nagarjuna, radicalized dependent origination into a critique of intrinsic nature. Yogacara, associated with figures such as Vasubandhu, examined consciousness, representation, and the structure of experience. Buddhist epistemologists such as Dignaga and Dharmakirti later reshaped logic and theories of knowledge.',
      'These developments are not merely later complications added to a simple original. They arise from pressures inside early teachings: if there is no self, what continues? If all is conditioned, what is liberation? If views bind, how should doctrine be used? If compassion matters, how does individual liberation relate to universal liberation? The Buddha remains the origin because these later systems keep returning to suffering, ignorance, dependent arising, and the path, even when their technical vocabularies become highly sophisticated.'
    ],['buddhist-philosophy','buddhist-epistemology','indian-philosophy'],['buddha','nagarjuna','vasubandhu','dignaga','dharmakirti'],['Pali Canon','Mulamadhyamakakarika']),
    section('misunderstandings-reading','Misunderstandings and a reading strategy',[
      'Common misunderstandings are easy to form. Buddhism is not simply pessimism; it diagnoses suffering in order to end it. Not-self is not self-hatred or denial of conventional persons. Detachment is not indifference to suffering, because compassion becomes central to the path. Karma is not fatalism. Meditation is not a shortcut around ethics. The Buddha teaching is demanding because it refuses both indulgence and metaphysical comfort. It asks readers to examine how suffering is actively produced.',
      'Begin with accessible early discourses on the four noble truths, dependent origination, not-self, mindfulness, and loving-kindness, along with selections from the Dhammapada. Read life stories as meaningful religious narratives while keeping historical caution. Then compare later Buddhist philosophical developments, especially Nagarjuna, to see how early restraint about speculative views becomes rigorous critique. A good reading question is always practical and philosophical at once: what does this teaching say exists, and how would seeing that change craving, conduct, and compassion?'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['buddha','nagarjuna'],['Dhammapada','Pali Canon'])
  ],
  nagarjuna:[
    section('overview','Emptiness as the deep meaning of dependent arising',[
      'Nagarjuna is one of the most important philosophers in Buddhist and global thought because he turns the Buddha teaching of dependent arising into a radical critique of intrinsic nature. He is associated with Madhyamaka, the middle way, and with the claim that all phenomena are empty. Emptiness does not mean that nothing exists. It means that things lack svabhava, independent self-being or essence. They exist dependently, conventionally, relationally, and causally, not from their own side as self-grounded realities.',
      'This insight is meant to free thought from two extremes: eternalism, which turns things into fixed essences, and nihilism, which denies conventional functioning. Nagarjuna argues that because things are empty, they can arise, change, act, and be known conventionally. If things possessed fixed essence, causal interaction would become unintelligible. His philosophy is therefore not a destruction of the world but a liberation from reifying the world. It is also a discipline against reifying Buddhist doctrine itself.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['nagarjuna','buddha'],['Mulamadhyamakakarika']),
    section('historical-context','Mahayana, scholastic debate, and uncertain dates',[
      'Nagarjuna is often dated around the second to third century CE, but the chronology is not fully secure. Traditional biographies surround him with miracle stories, links to serpent realms, and legendary retrieval of Mahayana scriptures. These narratives express religious authority but cannot be used straightforwardly as modern biography. The historical philosopher likely worked in an Indian Buddhist environment shaped by monastic learning, Abhidharma analysis, emerging Mahayana sutras, and debate with Buddhist and non-Buddhist schools.',
      'This context matters because Nagarjuna is not arguing in an empty space. Abhidharma traditions had developed precise analyses of experience, causation, and dharmas, sometimes treating basic factors as ultimately real in a technical sense. Mahayana texts such as the Prajnaparamita literature emphasized emptiness, nonattachment to views, and bodhisattva wisdom. Nagarjuna gives philosophical force to that vision. He shows that any attempt to locate final intrinsic reality in persons, things, causes, motion, time, or even nirvana collapses under analysis.'
    ],['buddhist-philosophy','indian-philosophy'],['nagarjuna','buddha','vasubandhu'],['Mulamadhyamakakarika','Prajnaparamita Sutras']),
    section('works-and-attribution','Works, attribution, and the core text',[
      'Many works are attributed to Nagarjuna, but attribution is complicated. The Mulamadhyamakakarika, often translated as Fundamental Verses on the Middle Way, is the central philosophical text. Other works such as the Vigrahavyavartani and Ratnavali are commonly associated with him, though scholarly confidence varies by text. Later traditions also attribute tantric, devotional, and medical materials to Nagarjuna or to figures bearing the same name. Responsible reading distinguishes the core Madhyamaka corpus from broader legendary attribution.',
      'The Mulamadhyamakakarika is terse, technical, and difficult. It proceeds through chapters on conditions, motion, sense faculties, aggregates, elements, desire, causation, self, time, suffering, compounded things, and nirvana. It does not build a metaphysical system in the usual way. It tests views that assume intrinsic nature and shows how those views fail. The text requires patient commentary because a short verse may presuppose debates in Buddhist scholasticism and Indian logic. Its brevity is part of its force.'
    ],['buddhist-philosophy','indian-philosophy','epistemology'],['nagarjuna'],['Mulamadhyamakakarika','Vigrahavyavartani','Ratnavali']),
    section('emptiness','What emptiness denies and what it preserves',[
      'Emptiness denies that things possess independent essence. It does not deny that tables, persons, actions, suffering, paths, or teachings function in ordinary and practical contexts. Nagarjuna repeatedly links emptiness with dependent designation. A chariot, to use a traditional Buddhist example, is not found as an essence apart from parts, arrangement, use, and naming. Yet the chariot can still carry someone conventionally. The same pattern applies more deeply to self, causation, and phenomena generally.',
      'This distinction is difficult because the mind tends to move from no essence to no existence. Nagarjuna resists that move. To be empty is to be dependently arisen, and to be dependently arisen is precisely to be capable of relation. A non-empty entity, fixed by its own nature, could not be affected or transformed. Emptiness therefore preserves the intelligibility of change, practice, and liberation. It is the middle way between substantialism and nihilism.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['nagarjuna','buddha'],['Mulamadhyamakakarika']),
    section('two-truths','The two truths and conventional reality',[
      'Nagarjuna uses the distinction between conventional truth and ultimate truth. Conventional truth includes ordinary language, practical distinctions, causal explanations, ethical responsibility, and the teachings used on the path. Ultimate truth is the emptiness of all phenomena, including the emptiness of the distinctions used conventionally. The two truths are not two separate worlds. They are two ways of understanding the same dependently arisen reality.',
      'This distinction prevents two opposite errors. If one rejects convention because all is empty, communication, practice, compassion, and the path collapse. If one clings to convention as ultimately grounded, one reifies what Buddhist analysis is meant to loosen. Nagarjuna says that without relying on convention, ultimate truth cannot be taught; without understanding ultimate truth, liberation cannot be attained. The conventional is therefore not trash to discard. It is the indispensable medium through which emptiness is realized.'
    ],['buddhist-philosophy','indian-philosophy','epistemology'],['nagarjuna','buddha'],['Mulamadhyamakakarika']),
    section('causation-and-motion','Causation, motion, and the critique of fixed entities',[
      'Nagarjuna examines causation with relentless precision. If an effect already exists in the cause, production becomes pointless; if it is wholly different, the connection becomes unintelligible; if it both exists and does not exist, contradiction follows; if neither, production disappears. These arguments are not meant to deny that seeds produce sprouts in ordinary life. They show that causal production cannot be explained by appealing to entities with intrinsic nature. Causation works only because things are relational and empty.',
      'The same strategy appears in analyses of motion, time, and change. A mover cannot be established apart from moving, motion cannot be found as an independent thing, and the path of motion cannot be divided into self-existing units without paradox. Such arguments sound destructive when read as abstract puzzles. Within Madhyamaka, they are therapeutic. They expose the tendency to imagine hidden essences beneath ordinary processes. Once that demand is released, conventional motion and causation can function without metaphysical burden.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['nagarjuna'],['Mulamadhyamakakarika']),
    section('self-and-suffering','Self, aggregates, suffering, and nirvana',[
      'Nagarjuna extends the Buddhist critique of self. The person is not identical with the aggregates, not wholly different from them, not their owner, and not found as a separate essence behind them. This analysis deepens the early teaching of not-self by showing that any attempt to make the self ultimately real generates contradictions. Yet persons still exist conventionally, perform actions, experience suffering, and follow the path. Conventional personhood is not abolished by the absence of intrinsic self.',
      'His treatment of nirvana is equally radical. Nirvana is not an independently existing realm set apart from samsara as an opposite substance. If samsara and nirvana were intrinsically separate, liberation could not bridge them. Nagarjuna famously argues that there is no ultimate difference between samsara and nirvana when both are understood as empty. This does not trivialize liberation. It means that bondage lies in grasping dependently arisen reality as intrinsically real, and freedom lies in seeing that very reality without reification.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['nagarjuna','buddha'],['Mulamadhyamakakarika']),
    section('method-and-prasanga','Method, reductio, and the question of thesis',[
      'Nagarjuna often argues by prasanga, reductio or consequence. He takes an opponent view and shows that its assumptions lead to contradiction, incoherence, or the loss of what the view was meant to explain. This method has led to debate about whether Nagarjuna has a thesis of his own. Some traditions emphasize that Madhyamaka does not advance a competing metaphysical position; it removes all views that grasp intrinsic nature. Others argue that the claim of emptiness has a positive philosophical role.',
      'The debate is not merely technical. If emptiness becomes a doctrine held as ultimate, it turns into the very kind of view it was meant to cure. Nagarjuna warns that emptiness wrongly grasped is dangerous. The method therefore demands unusual discipline from readers. One must use arguments to loosen reification without making the argument itself into a new foundation. Madhyamaka is philosophy used against the deepest habits of philosophical possession.'
    ],['buddhist-philosophy','indian-philosophy','epistemology'],['nagarjuna','buddha'],['Mulamadhyamakakarika','Vigrahavyavartani']),
    section('ethics-and-compassion','Emptiness, ethics, and the bodhisattva path',[
      'A common misunderstanding is that emptiness undermines ethics. If nothing has essence, why should actions matter? Nagarjuna answer is the reverse: because beings and suffering arise dependently, actions matter profoundly. Harm, compassion, ignorance, and wisdom are all conditioned processes with consequences. Ethical practice belongs to conventional truth, but conventional truth is not optional. Without compassion, emptiness becomes a cold abstraction; without emptiness, compassion can become attached to fixed identities and despair.',
      'Mahayana context matters here. The bodhisattva path joins wisdom and compassion. Wisdom sees that persons and phenomena lack intrinsic nature; compassion responds to suffering without reifying savior, sufferer, or saved. Nagarjuna is therefore not only a logician of negation. His critique serves liberation. By loosening the grasping that creates self-protective fixation, emptiness makes more flexible and less possessive compassion possible. Ethics remains active precisely because there are dependent beings who suffer.'
    ],['buddhist-philosophy','indian-philosophy','ethics'],['nagarjuna','buddha'],['Mulamadhyamakakarika','Ratnavali']),
    section('relation-to-earlier-buddhism','Relation to early Buddhism and Abhidharma',[
      'Nagarjuna presents himself as recovering the deep meaning of the Buddha teaching rather than inventing a new doctrine. Dependent origination, not-self, the middle way, and the critique of views all have early Buddhist roots. His originality lies in applying these insights to every candidate for ultimate status, including the basic factors analyzed by scholastic traditions. If dharmas are treated as intrinsically real, he argues, the Buddhist path has not gone far enough.',
      'This relation to Abhidharma is complex. Abhidharma analysis can be understood as a careful tool for deconstructing the person into processes. Nagarjuna worries that the tool can harden into a new ontology. He therefore deconstructs the deconstructive categories. Later Buddhist traditions would debate whether Madhyamaka is the final interpretation of the Buddha, how it relates to Yogacara, and whether emptiness should be read through logic, meditation, or devotional practice. Nagarjuna becomes a turning point because he radicalizes Buddhist anti-essentialism.'
    ],['buddhist-philosophy','buddhist-epistemology','indian-philosophy'],['nagarjuna','buddha','vasubandhu','dignaga','dharmakirti'],['Mulamadhyamakakarika']),
    section('influence','Influence across Buddhist worlds and beyond',[
      'Nagarjuna shaped Indian Buddhist debate and later Tibetan, East Asian, and global Buddhist philosophy. Madhyamaka became central in Tibetan scholastic traditions, where interpretations of Prasangika and Svatantrika methods generated sophisticated debates. In East Asia, emptiness thought interacted with Chinese Buddhist schools, Daoist vocabulary, and later Chan and Zen reflection. The philosophical vocabulary traveled, but it did not remain unchanged. Each context reinterpreted emptiness through its own institutions and practices.',
      'His influence also extends into comparative philosophy. Readers have compared Nagarjuna with skepticism, Kantian critique, analytic metaphysics, deconstruction, pragmatism, and process thought. Such comparisons can illuminate but also mislead. Nagarjuna is not simply saying that knowledge is impossible, that everything is language, or that reality is whatever works. His arguments are rooted in Buddhist liberation, dependent arising, and the ending of grasping. Comparative reading is strongest when it preserves that soteriological setting.'
    ],['buddhist-philosophy','buddhist-epistemology','indian-philosophy'],['nagarjuna','buddha','vasubandhu'],['Mulamadhyamakakarika']),
    section('misunderstandings-reading','Misunderstandings and a reading strategy',[
      'The largest misunderstanding is nihilism. Emptiness does not mean nothing exists or nothing matters. Another misunderstanding is mystification, as if emptiness were a hidden absolute behind appearances. Nagarjuna denies that too. A third mistake is turning the two truths into two realms, one fake and one real. Conventional truth is the functioning of dependent life; ultimate truth is its emptiness of intrinsic nature. They are inseparable. The aim is not to replace ordinary responsibility with a superior vocabulary, but to stop clinging to any vocabulary as final.',
      'A good reading path begins with early Buddhist teachings on dependent origination and not-self, then moves to selected chapters of the Mulamadhyamakakarika with a reliable commentary. Read slowly and ask what assumption of intrinsic nature is being tested. Keep returning to the practical question: how does this argument loosen grasping? Then read later Madhyamaka interpretation to see why readers disagree about method and thesis. Nagarjuna rewards patience because his philosophy changes what one expects an explanation to be.'
    ],['buddhist-philosophy','indian-philosophy','metaphysics'],['nagarjuna','buddha'],['Mulamadhyamakakarika'])
  ],
  shankara:[
    section('overview','Nondual Vedanta and the knowledge of Brahman',[
      'Shankara, often called Adi Shankara, is the most influential classical philosopher associated with Advaita Vedanta. His central teaching is nonduality: the ultimate reality, Brahman, is not one object among others, and the deepest self, atman, is not finally separate from Brahman. Liberation comes through knowledge that removes ignorance about this identity. This is not merely a theory about the world. It is a disciplined interpretation of scripture, reason, renunciation, and spiritual practice aimed at freedom from bondage.',
      'Shankara is often summarized in slogans such as the world is illusion or the self is Brahman. Those slogans are dangerous when detached from his method. He does not deny ordinary experience as if it were nothing at all. He distinguishes levels of reality, examines error, interprets Upanisadic texts, and argues against rival accounts of self, ritual, causation, and liberation. His thought stands at the intersection of metaphysics, hermeneutics, philosophy of religion, epistemology, and the practical question of how ignorance can end.'
    ],['vedanta','indian-philosophy','metaphysics'],['shankara','ramanuja'],['Brahma Sutra Bhashya','Upadesasahasri']),
    section('historical-context','Early medieval India and contested Vedanta',[
      'Shankara is commonly placed in the eighth century CE, though exact dates remain debated. He worked in an India shaped by Brahmanical traditions, Buddhist philosophical schools, Jain thought, devotional movements, temple cultures, ritual practice, and sophisticated debate. Vedanta itself was not yet a single settled doctrine. It was a field of interpretation centered on the Upanisads, Bhagavad Gita, and Brahma Sutras, with rival accounts of Brahman, self, world, ritual, and liberation.',
      'This context matters because Shankara is not simply restating ancient scripture. He is constructing an interpretation under pressure from competing views. Buddhist thinkers had developed powerful analyses of momentariness, no-self, emptiness, consciousness, and knowledge. Mimamsa defended Vedic ritual authority. Samkhya offered dualism of purusa and prakriti. Theistic and devotional currents emphasized personal relation to the divine. Shankara argues for a nondual reading that preserves scriptural authority while making knowledge, rather than ritual action, the direct means to liberation.'
    ],['vedanta','indian-philosophy','philosophy-of-religion'],['shankara','buddha','nagarjuna'],['Upanisads','Bhagavad Gita','Brahma Sutras']),
    section('biography-and-legend','Biography, monastic memory, and legendary expansion',[
      'Traditional biographies portray Shankara as a brilliant renunciant who traveled across India, debated rival teachers, wrote major commentaries, established monastic centers, and died young. These narratives are important for the Advaita community, but many details are historically uncertain and often shaped by later institutional memory. The image of Shankara as a national religious unifier or founder of exactly defined institutions should be handled cautiously. The historical philosopher is easier to see in the commentarial works than in later hagiography.',
      'This caution does not make the biographies meaningless. They express how later Advaitins understood the philosophical life: renunciation, scriptural mastery, debate, teaching lineage, and the defense of nondual knowledge against ritualism and rival metaphysics. The stories also show how philosophy becomes institution. A thinker whose arguments concern the unreality of separateness becomes the center of durable communities, orders, and pedagogical traditions. The tension between nondual insight and institutional memory is part of Shankara reception.'
    ],['vedanta','indian-philosophy','philosophy-of-religion'],['shankara'],['Brahma Sutra Bhashya']),
    section('works-and-attribution','Commentaries and attribution cautions',[
      'The most important works associated with Shankara are commentaries on the Brahma Sutras, major Upanisads, and Bhagavad Gita, along with independent teaching texts such as the Upadesasahasri. Attribution is not equally secure for every work traditionally assigned to him. Later Advaita produced many manuals, hymns, and summaries under Shankara name or influence. Responsible study distinguishes the core commentarial corpus from broader devotional and pedagogical literature.',
      'The commentarial form is essential. Shankara does not present Advaita as a private invention. He argues that the highest teaching of the Upanisads is nondual Brahman and that apparently pluralistic passages must be interpreted in light of that liberating knowledge. The Brahma Sutra commentary is especially important because it positions Advaita within a contested exegetical field. Shankara reads scripture with philosophical arguments about self, error, causation, and liberation. For him, interpretation is not secondary to philosophy; it is one of its main forms.'
    ],['vedanta','indian-philosophy','epistemology'],['shankara'],['Brahma Sutra Bhashya','Upadesasahasri','Bhagavad Gita Bhashya']),
    section('brahman-and-atman','Brahman, atman, and nonduality',[
      'Advaita Vedanta teaches that Brahman is the ultimate reality: unconditioned, nondual, not limited by attributes in the highest sense, and not one being among others. The self, atman, when stripped of mistaken identification with body, senses, mind, and social personality, is not different from Brahman. This identity is not discovered by making the individual ego divine. The ego is part of the mistaken superimposition. The true self is the witnessing consciousness that cannot be objectified as one more thing.',
      'This teaching depends on careful negation. Brahman is not grasped through ordinary object knowledge because every object is limited and known within consciousness. Upanisadic statements such as tat tvam asi are interpreted to reveal an identity that ordinary experience obscures. Shankara must therefore explain how difference appears, how ignorance operates, and how language can point beyond its ordinary objectifying function. Nonduality is not arithmetic oneness. It is the denial that ultimate reality is divided into independent selves and things.'
    ],['vedanta','indian-philosophy','metaphysics'],['shankara','ramanuja'],['Upanisads','Brahma Sutra Bhashya']),
    section('avidya-and-superimposition','Ignorance, superimposition, and error',[
      'Shankara explains bondage through avidya, ignorance, and adhyasa, superimposition. People mistakenly superimpose the properties of body, mind, agency, pleasure, pain, caste, gender, and biography onto the self, and superimpose consciousness onto what is not self. The result is the ordinary sense of being a finite doer and enjoyer moving through a world of separate objects. This error is not just an intellectual mistake like a wrong answer on a test. It structures lived experience.',
      'His famous discussions of error, often illustrated by mistaking a rope for a snake, show how something can appear and affect conduct without being ultimately real in the way it appears. The snake frightens, but the rope was the underlying reality. Similarly, the world of plurality functions within experience, but its independent separateness is not ultimate. Critics have long asked where ignorance resides and how ignorance can arise if Brahman alone is ultimately real. Advaita develops complex answers, but the tension remains philosophically central.'
    ],['vedanta','indian-philosophy','epistemology'],['shankara'],['Brahma Sutra Bhashya','Upadesasahasri']),
    section('maya-and-reality-levels','Maya and levels of reality',[
      'Maya is often translated as illusion, but that translation easily misleads. In Advaita, the world is not absolute nothing. It is empirically experienced, causally ordered, morally consequential, and scripturally addressed. Its unreality is relative to Brahman, the ultimate reality that does not depend on it. Later Advaita often distinguishes paramarthika reality, ultimate reality; vyavaharika reality, empirical or transactional reality; and pratibhasika reality, merely apparent reality such as dream or illusion.',
      'These distinctions help Shankara avoid crude world denial. Fire burns, ethical action matters, teaching occurs, and liberation must be pursued within empirical life. Yet empirical life is not final because it depends on ignorance of nonduality. When knowledge arises, the world is not destroyed like an object smashed by a hammer; it is known differently, as lacking independent ultimate status. This account gives Advaita both its subtlety and its difficulty. It must preserve ordinary functioning without granting it final reality.'
    ],['vedanta','indian-philosophy','metaphysics'],['shankara'],['Brahma Sutra Bhashya','Upadesasahasri']),
    section('scripture-and-reason','Scripture, reason, and liberating knowledge',[
      'Shankara gives scripture a distinctive role. Brahman cannot be known as an ordinary perceptual object or inferred like a hidden cause, because Brahman is the ground of the knower rather than an item inside the world. The Upanisads therefore function as a pramana, a means of knowledge, for what ordinary means cannot disclose. This does not mean that reason is abandoned. Reason is used to interpret scripture, remove contradictions, refute rival views, and prepare the mind to understand the teaching.',
      'The relation between scripture and reason is delicate. Shankara does not allow reasoning to invent Brahman independently of revelation, but he also does not treat sacred words as magic sounds that work without understanding. The student must hear, reflect, and deeply contemplate the teaching until ignorance is removed. Language points by negation, implication, and carefully interpreted identity statements. In this sense, Advaita is a hermeneutical philosophy: liberation depends on learning how to understand words that undo the ordinary structure of self-understanding.'
    ],['vedanta','indian-philosophy','epistemology'],['shankara'],['Upanisads','Brahma Sutra Bhashya','Upadesasahasri']),
    section('knowledge-action-and-liberation','Knowledge, action, and liberation',[
      'A major Shankara claim is that liberating knowledge, not ritual action, directly brings moksha. Action produces results in time; it can purify, discipline, or prepare, but it cannot produce the already-real identity of atman and Brahman. If liberation were a product, it would be impermanent. Knowledge removes ignorance about what is already the case. This is why Shankara criticizes views that make Vedic ritual the primary path to final liberation.',
      'This does not make ethical and spiritual discipline irrelevant. Qualifications such as discrimination, dispassion, self-control, endurance, concentration, and desire for liberation prepare the seeker for knowledge. Renunciation plays a central role because identification with action, possession, and social role reinforces bondage. The tension is practical: if knowledge alone liberates, why so much preparation? Shankara answer is that preparation does not produce liberation directly; it makes the mind capable of receiving and stabilizing the liberating insight.'
    ],['vedanta','indian-philosophy','ethics'],['shankara'],['Bhagavad Gita Bhashya','Upadesasahasri']),
    section('debates-with-rivals','Debates with Buddhist and Brahmanical rivals',[
      'Shankara argues against several rival positions. Against Buddhist no-self and momentariness, he defends a stable witnessing consciousness without making it an object. Against some Buddhist idealist or emptiness views as he understands them, he argues that denial of a real self undermines continuity and knowledge. Modern readers should be careful: Shankara debates Buddhist positions through the categories and polemics available to him, and those representations may not match every Buddhist school on its own terms.',
      'He also debates Samkhya dualism, which distinguishes purusa and prakriti; Nyaya realism, which defends a pluralistic ontology and inference; and Mimamsa ritualism, which emphasizes Vedic injunctions and action. These debates show that Advaita is not only mystical assertion. It is a rigorous intervention in Indian philosophical argument about self, causation, language, knowledge, and liberation. Later Vedantins such as Ramanuja would criticize Shankara in turn, especially over whether Brahman is without qualities in the highest sense and whether the world is too diminished by Advaita.'
    ],['vedanta','indian-philosophy','buddhist-philosophy'],['shankara','buddha','nagarjuna','ramanuja'],['Brahma Sutra Bhashya']),
    section('devotion-ethics-and-practice','Devotion, ethics, and the lived Advaita path',[
      'Shankara is sometimes portrayed as purely intellectual, but this is too narrow. His tradition includes devotion, meditation, renunciation, teacher-student transmission, and disciplined ethical preparation. In his commentaries, devotion can be understood as steady contemplation of the truth of the self or as worship within empirical religious life. Saguna Brahman, Brahman with attributes, has an important place in practice and devotion, even though nirguna Brahman, Brahman without limiting attributes, is ultimate in Advaita interpretation.',
      'Ethically, Advaita can be misunderstood as making the world morally irrelevant. Shankara does not teach that ordinary conduct ceases to matter for seekers. Noninjury, truthfulness, self-control, and detachment help purify the mind. The difficulty is how to relate nondual knowledge to social obligation. If ultimate selfhood is beyond role, what becomes of role-based duty? Advaita answers through levels of reality and stages of practice, but the question remains important, especially when modern readers ask how nonduality relates to justice, embodiment, and social difference.'
    ],['vedanta','indian-philosophy','ethics'],['shankara'],['Bhagavad Gita Bhashya','Upadesasahasri']),
    section('influence-and-contestation','Influence, Ramanuja, and later Vedanta',[
      'Shankara shaped Advaita Vedanta so deeply that later discussions of nonduality often move through his vocabulary, even when they revise it. Monastic lineages, commentarial traditions, teaching manuals, and modern Hindu reform movements all draw on Shankara in different ways. His influence is not limited to technical philosophy. He became a symbol of scriptural intelligence, renunciation, debate, and the possibility that liberation depends on knowledge of the deepest self.',
      'His dominance also provoked major alternatives. Ramanuja develops Vishishtadvaita, often translated as qualified nondualism, defending a real relation between Brahman, souls, and world, and giving devotion a more central theological structure. Other Vedanta schools argue for dualism, difference-and-nondifference, or devotional theism. These debates show that Vedanta is not identical with Advaita. Shankara is a central systematizer, not the owner of the whole tradition. Reading him beside Ramanuja makes the stakes of interpretation much clearer.'
    ],['vedanta','indian-philosophy','philosophy-of-religion'],['shankara','ramanuja'],['Brahma Sutra Bhashya']),
    section('misunderstandings-reading','Misunderstandings and a reading strategy',[
      'The most common misunderstanding is that Shankara says the world is simply unreal. A better formulation is that the world is empirically real but ultimately dependent and not separate from Brahman. Another misunderstanding is that atman equals the psychological ego. Advaita denies that the ego is the true self. A third is that nonduality erases practice. In Shankara, hearing, reflection, contemplation, discipline, and renunciation all matter as means by which ignorance is removed.',
      'A strong reading path begins with a clear introduction to the Upanisadic background, then selections from the Upadesasahasri, then guided passages from the Brahma Sutra Bhashya and Bhagavad Gita commentary. Track how Shankara uses scripture, reason, and examples of error. Read criticisms from Ramanuja or other Vedantins to avoid thinking Advaita is the only possible interpretation of Vedanta. The best question to keep alive is precise: what exactly is denied by nonduality, and what remains valid at the empirical level of practice?'
    ],['vedanta','indian-philosophy','metaphysics'],['shankara','ramanuja'],['Upadesasahasri','Brahma Sutra Bhashya','Bhagavad Gita Bhashya'])
  ]
};
